  while (queue.length > 0) {
    const levelSize = queue.length;
    const level: number[] = [];
    for (let i = 0; i < levelSize; i++) {
      const node = queue.shift()!;
      level.push(node.val);
      if (node.left) queue.push(node.left);
      if (node.right) queue.push(node.right);
    }
    result.push(level);
  }
  return result;
}
```

**Типичная ошибка:** Сохраняйте levelSize перед внутренним циклом, чтобы избежать обработки новых узлов в текущей итерации.

answer.en:
### Two Pointers for In-Place Deduplication

In-place means modifying the original array without extra space. Use one pointer for iteration and one for placing unique elements. The array is logically shortened while preserving order.

```typescript
function removeDuplicates(arr: number[]): number {
  let writePointer = 0;
  for (let readPointer = 1; readPointer < arr.length; readPointer++) {
    if (arr[readPointer] !== arr[writePointer]) {
      writePointer++;
      arr[writePointer] = arr[readPointer];
    }
  }
  return writePointer + 1;
}
```

**Common interview trap:** Don't use a Set or create a new array; modify in-place by moving elements and tracking the write position.

answer.ru:
### Два указателя для удаления дубликатов на месте

На месте означает изменение исходного массива без дополнительного пространства. Используйте один указатель для итерации и один для размещения уникальных элементов. Массив логически сокращается с сохранением порядка.

```typescript
function removeDuplicates(arr: number[]): number {
  let writePointer = 0;
  for (let readPointer = 1; readPointer < arr.length; readPointer++) {
    if (arr[readPointer] !== arr[writePointer]) {
      writePointer++;
      arr[writePointer] = arr[readPointer];
    }
  }
  return writePointer + 1;
}
```

**Типичная ошибка:** Не используйте Set или новый массив; модифицируйте на месте, перемещая элементы и отслеживая позицию записи.

answer.en:
### Merge Sort vs Quick Sort

Merge sort guarantees O(n log n) and is stable, making it better for linked lists or when worst-case performance matters. Quick sort is faster on average (O(n log n)) and uses less space, but can degrade to O(n²) with poor pivot selection.

```typescript
function mergeSort(arr: number[]): number[] {
  if (arr.length <= 1) return arr;
  const mid = Math.floor(arr.length / 2);
  const left = mergeSort(arr.slice(0, mid));
  const right = mergeSort(arr.slice(mid));
  return merge(left, right);
}
function merge(left: number[], right: number[]): number[] {
  const result: number[] = [];
  let l = 0, r = 0;
  while (l < left.length && r < right.length) {
    result.push(left[l] < right[r] ? left[l++] : right[r++]);
  }
  return result.concat(left.slice(l), right.slice(r));
}
```

**Common interview trap:** Mention stability and worst-case guarantees when choosing merge sort; don't just focus on average performance.

answer.ru:
